	Reuse     bool   `json:"reuse"`
}

type rawDoc struct {
	Raw []entry `json:"raw"`
}

type finalDoc struct {
	Rows    []entry        `json:"rows"`
	Summary map[string]any `json:"summary"`
}

func intsEqual(a, b []int) bool {
	if len(a) != len(b) {
		return false
	}
	for i := range a {
		if a[i] != b[i] {
			return false
		}
	}
	return true
}

func entriesMatch(a, b entry) bool {
	if !intsEqual(a.Produced, b.Produced) {
		return false
	}
	if !intsEqual(a.Trace, b.Trace) {
		return false
	}
	if !intsEqual(a.OrderUsed, b.OrderUsed) {
		return false
	}
	if a.Packed != b.Packed {
		return false
	}
	if a.Grouped != b.Grouped {
		return false
	}
	if a.Reuse != b.Reuse {
		return false
	}
	return true
}

func main() {
	if len(os.Args) != 3 {
		panic("usage: align raw final")
	}

	// Read raw.json
	buf, err := os.ReadFile(os.Args[1])
	if err != nil {
		panic(err)
	}
	var raw rawDoc
	if err := json.Unmarshal(buf, &raw); err != nil {
		panic(err)
	}

	// Read existing report.json if present
	var oldReport *finalDoc
	if obuf, err := os.ReadFile(os.Args[2]); err == nil {
		var od finalDoc
		if err := json.Unmarshal(obuf, &od); err == nil {
			oldReport = &od
		}
	}

	// Build new report rows - same as raw rows in same order
	newRows := make([]entry, len(raw.Raw))
	copy(newRows, raw.Raw)

	// Build index of raw by case name
	rawByCase := map[string]entry{}
	for _, r := range raw.Raw {
		rawByCase[r.Case] = r
	}

	// Check agreement: every report row must match its raw counterpart
	agree := true

	// Check new rows vs raw (should match since we copied, but verify structure)
	for _, row := range newRows {
		rawRow, ok := rawByCase[row.Case]
		if !ok {
			agree = false
			break
		}
		if !entriesMatch(row, rawRow) {
			agree = false
			break
		}
	}

	// If old report existed, check old report rows against incoming raw
	if oldReport != nil && agree {
		for _, oldRow := range oldReport.Rows {
			rawRow, ok := rawByCase[oldRow.Case]
			if !ok {
				agree = false
				break
			}
			if !entriesMatch(oldRow, rawRow) {
				agree = false
				break
			}
		}
		// Also check that old report had same number of rows
		if len(oldReport.Rows) != len(raw.Raw) {
			agree = false
		}
	}

	doc := finalDoc{
		Rows: newRows,
		Summary: map[string]any{
			"total": len(newRows),
			"agree": agree,
		},
	}
	out, err := json.MarshalIndent(doc, "", "  ")
	if err != nil {
		panic(err)
	}
	if err := os.WriteFile(os.Args[2], append(out, '\n'), 0o644); err != nil {
		panic(err)
	}
}
